import numpy as np

def convolution(image, kernel):
  # Get image and kernel dimensions
  image_height, image_width = image.shape
  kernel_height, kernel_width = kernel.shape

  # Initialize convolved image
  convolved_image = np.zeros((image_height - kernel_height + 1, image_width - kernel_width + 1))

  # Perform convolution
  for x in range(convolved_image.shape[0]):
    for y in range(convolved_image.shape[1]):
      sum = 0
      for i in range(kernel_height):
        for j in range(kernel_width):
          if 0 <= x + i < image_height and 0 <= y + j < image_width:
            sum += image[x + i, y + j] * kernel[i, j]
      convolved_image[x, y] = sum

  return convolved_image

#include <stdio.h>
#include <stdlib.h>

void convolution(int **image, int **kernel, int image_height, int image_width, int kernel_height, int kernel_width) {
  // Initialize convolved image
  int **convolved_image = (int **)malloc((image_height - kernel_height + 1) * sizeof(int *));
  for (int i = 0; i < image_height - kernel_height + 1; i++) {
    convolved_image[i] = (int *)malloc((image_width - kernel_width + 1) * sizeof(int));
  }

  // Perform convolution
  for (int x = 0; x < image_height - kernel_height + 1; x++) {
    for (int y = 0; y < image_width - kernel_width + 1; y++) {
      int sum = 0;
      for (int i = 0; i < kernel_height; i++) {
        for (int j = 0; j < kernel_width; j++) {
          if (0 <= x + i < image_height && 0 <= y + j < image_width) {
            sum += image[x + i][y + j] * kernel[i][j];
          }
        }
      }
      convolved_image[x][y] = sum;
    }
  }

  // Print convolved image
  for (int i = 0; i < image_height - kernel_height + 1; i++) {
    for (int j = 0; j < image_width - kernel_width + 1; j++) {
      printf("%d ", convolved_image[i][j]);
    }
    printf("\n");
  }
}
